<?php
session_start();require_once '../config/base.php';
if(!isset($_SESSION['admin_id'])){header('Location: '.BASE_URL.'/login.php');exit;}
require_once '../config/db.php';
$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){
  $title=trim($_POST['title']??'');$desc=trim($_POST['description']??'');$cat=trim($_POST['category']??'');$loc=trim($_POST['location']??'');$date=$_POST['event_date']??'';$dl=$_POST['registration_deadline']??'';$maxp=intval($_POST['max_participants']??100);$price=floatval($_POST['price']??0);$org=trim($_POST['organizer']??'');
  if(!$title||!$cat||!$date){$error='Title, category and date are required.';}
  else{$s=$pdo->prepare("INSERT INTO events(title,description,category,location,event_date,registration_deadline,max_participants,price,organizer,created_by)VALUES(?,?,?,?,?,?,?,?,?,?)");$s->execute([$title,$desc,$cat,$loc,$date,$dl?:null,$maxp,$price,$org,$_SESSION['admin_id']]);header('Location: '.BASE_URL.'/admin/manage_events.php?msg=added');exit;}
}
?>
